// TODO: Create a Countdown class
// - constructor(start) stores the starting number
// - implement [Symbol.iterator]() that returns an iterator
// - the iterator yields start, start-1, ..., 1

// After implementing, this code should work:
// const c = new Countdown(5);
// for (const n of c) { process.stdout.write(n + ' '); }
// console.log();
// console.log([...new Countdown(3)]);

exercises.solution:
class Countdown {
  constructor(start) {
    this.start = start;
  }

  [Symbol.iterator]() {
    let current = this.start;
    return {
      next() {
        if (current >= 1) {
          return { value: current--, done: false };
        }
        return { value: undefined, done: true };
      }
    };
  }
}

const c = new Countdown(5);
for (const n of c) {
  process.stdout.write(n + ' ');
}
console.log();
console.log([...new Countdown(3)]);

