const config = {
  server: {
    host: 'localhost',
    port: 0
  },
  // database key is missing entirely
  logging: {
    level: 'info'
  }
};

// TODO: Use optional chaining + nullish coalescing to:
// 1. Read config.server.host, default 'unknown' -> should be 'localhost'
// 2. Read config.database?.port, default 5432 -> should be 5432 (database missing)
// 3. Read config.logging?.file?.path, default 'stdout' -> should be 'stdout'
// 4. Show the ?? vs || difference for config.server.port (which is 0)
//    Log: "port ??: " + result with ??   (should preserve 0)
//    Log: "port ||: " + result with ||   (should replace with 3000)

exercises.solution:
const config = {
  server: {
    host: 'localhost',
    port: 0
  },
  logging: {
    level: 'info'
  }
};

console.log('host:', config.server?.host ?? 'unknown');
console.log('db port:', config.database?.port ?? 5432);
console.log('log path:', config.logging?.file?.path ?? 'stdout');
console.log('port ??:', config.server.port ?? 3000);
console.log('port ||:', config.server.port || 3000);

